#include <bits/stdc++.h>
using namespace std;
const int N=1e5,inf=0x3f3f3f3f;
int n,a[N];
struct node
{
	int l,r,op;
};
vector<node> v;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cout<<"? "<<i<<" "<<i<<"\n";
		cout<<flush;
		cin>>a[i];
	}
	int flag=a[1],l=1;
	for(int i=1;i<=n;i++)
	{
		if(a[i]!=flag)
		{
			v.push_back(node{l,i-1,flag});
			flag=a[i];
			l=i;
		}
	}
	v.push_back(node{l,n,flag});
	int z=inf,f=inf,tmp;
	flag=tmp=a[1];
	for(int i=0;i<v.size();i++)
	{
		node t=v[i];
		if(t.op==0)
		{
			if(f==inf||flag==1) f=t.l;
		}
		else
		{
			if(z==inf||flag==0) z=t.l;
		}
		if(i==0) continue;
		cout<<"? "<<min(z,f)<<" "<<v[i].r<<"\n";
		cout<<flush;
		int x;
		cin>>x;
		int x2=2;
		if(max(z,f)!=inf)
		{
			if(max(z,f)==v[i].r) x2=a[v[i].r];
			else
			{
				cout<<"? "<<max(z,f)<<" "<<v[i].r<<"\n";
				cout<<flush;
				cin>>x2;
			}
		}
		if(x2!=tmp)
		{
			if(tmp==0) f=inf;
			else z=inf;
		}
		if(x!=flag)
		{
			if(flag==0) f=inf;
			else z=inf;
		}
		flag=x;
		tmp=!x;
	}
//	cout<<flag<<' ';
	if(flag==0) cout<<"! "<<f<<" "<<min(n,z-1);
	else cout<<"! "<<z<<" "<<min(n,f-1);
	return 0;
}
